import{_ as i,c as a,o as p,ae as t}from"./chunks/framework.CMFi8ROq.js";const l="/mrdu/assets/weixin-login-flow.CwHOkvnQ.png",o="/mrdu/assets/jd-login-page.BR6_056R.png",r="/mrdu/assets/login-via-weixin.DYuhmroU.png",s="/mrdu/assets/weixin-app-auth.BgRFwPlO.png",n="/mrdu/assets/login-via-kuaijie.CD8TQOgr.png",c="/mrdu/assets/jd-auth-apply.Mo2_8MBT.png",d="/mrdu/assets/weixin-login-roles.CT_egNOo.png",_="/mrdu/assets/jd-wx-login.BSJ7IjOz.png",m="/mrdu/assets/wx-qr-connect.BkSwLm-D.png",u="/mrdu/assets/wx-l-qrconnect.PCyc60mz.png",P=JSON.parse('{"title":"微信扫码登录实现","description":"","frontmatter":{},"headers":[],"relativePath":"weixin/微信扫码登录实现.md","filePath":"weixin/微信扫码登录实现.md","lastUpdated":1775178454000}'),g={name:"weixin/微信扫码登录实现.md"};function h(x,e,f,w,q,b){return p(),a("div",null,e[0]||(e[0]=[t('<h1 id="微信扫码登录实现" tabindex="-1">微信扫码登录实现 <a class="header-anchor" href="#微信扫码登录实现" aria-label="Permalink to &quot;微信扫码登录实现&quot;">​</a></h1><h2 id="网页端微信扫码登录" tabindex="-1">网页端微信扫码登录 <a class="header-anchor" href="#网页端微信扫码登录" aria-label="Permalink to &quot;网页端微信扫码登录&quot;">​</a></h2><p>“网页端微信扫码登录”是指当我们登录某些网站（第三方网站）时使用微信进行扫码进行登录的过程。</p><ul><li>第三方网站把身份验证环节委托给微信，从而获取安全地获取用户身份。</li><li>通过扫码的方式进行登录，简化了登录过程。</li></ul><p>这是<strong>微信官方提供的能力</strong>，<a href="https://developers.weixin.qq.com/doc/oplatform/developers/dev/auth/web.html" target="_blank" rel="noreferrer">官方文档</a>在“网站应用授权登录”开发有详细的说明。</p><h3 id="使用说明" tabindex="-1">使用说明 <a class="header-anchor" href="#使用说明" aria-label="Permalink to &quot;使用说明&quot;">​</a></h3><p>第三方网站使用这些能力是有条件的。</p><ul><li>第三方网站使用通过微信扫码登录不是免费的（具体费用参考官网，目前是300元）。</li><li>在微信开放平台注册开发者账号，创建一个网站应用，通过审核后获得该网站相应的 <code>AppID</code> （应用标识）和 <code>AppSecret</code> （应用密钥，仅后端存储，严禁暴露前端）。</li></ul><h3 id="交互过程" tabindex="-1">交互过程 <a class="header-anchor" href="#交互过程" aria-label="Permalink to &quot;交互过程&quot;">​</a></h3><p>下面以“京东网站”为例，说明微信扫码登录的前端交互过程。</p><p><img src="'+l+'" alt="微信扫码登录交互过程"></p><ol><li><p>第三方网站有下面两种方式展示微信二维码。这两种方式基本上是一样的。</p><ul><li>在第三方网站的登录页面内嵌微信二维码。</li><li>点击“微信登录”按钮跳转到微信扫码登录页面。</li></ul><p><img src="'+o+'" alt="京东登录页面"></p></li><li><p>点击“微信登录”按钮后就跳转到下面的“微信扫码登录页面”，这个页面是微信官方提供的。</p><p><img src="'+r+'" alt="微信扫码登录页面"></p></li><li><p>“微信扫码登录页面”会向浏览器请求设备上应用的访问权限，判断当前设备是否存在<strong>已经登录</strong>并且处于<strong>非锁定状态</strong>的微信客户端。</p><p><img src="'+s+'" alt="微信设备访问申请"></p></li><li><p>如果存在，则会优先使用已登录的账号进行快捷登录。</p><p><img src="'+n+'" alt="微信快捷登录"></p></li><li><p>无论是“快捷登录”还是“微信扫码登录”，实际上都是一次授权的过程。</p><p><img src="'+c+'" alt="第三方网站申请微信授权"></p></li><li><p>用户同意了第三方网站的授权后，第三方网站会收到微信的授权回调通知，然后就可以获取到用户的微信身份信息，从而实现登录。</p></li></ol><h3 id="实现流程解析" tabindex="-1">实现流程解析 <a class="header-anchor" href="#实现流程解析" aria-label="Permalink to &quot;实现流程解析&quot;">​</a></h3><p>其实整个流程的实现并不复杂，微信官方为了身份校验过程标准化、防止敏感信息泄露、规范登录过程中的会话管理、降低第三方网站开发成本，尽可能的将整个登录过程进行封装，从而便于开发者对接。</p><p>从业务的角度来讲，整个登录过程涉及到 3 个核心角色：微信用户、第三方网站应用、微信开放平台（微信服务器）。</p><p><img src="'+d+'" alt="微信登录角色"></p><p>但是从开发的角度来讲，则整个流程涉及到 4 个节点：用户手机客户端、浏览器（第三方网站应用前端和微信二维码页面）、第三方网站应用后端、微信服务器。</p><p>核心交互链路：网页前端发起登录请求 → 网站后端重定向到微信登录页面（展示二维码） → 实时获取当前二维码对应的会话状态 → 用户手机微信扫码 → 手机微信解析二维码信息并向微信服务器发起授权请求 → 用户确认授权 → 微信服务器同步授权信息给网站后端 → 网站后端生成登录态并通知网页前端 → 网页端完成登录。</p><p>下面我们拆解一下整个登录流程，依然以“京东”为例。</p><ol><li><p>点击“微信登录”按钮后，会向网站后端发送一个“获取微信登录二维码”的请求。</p><p><img src="'+_+'" alt="获取微信登录二维码请求"></p></li><li><p>网站后端收到请求后（请求状态是<code>302</code>），会重定向到微信官网的“二维码获取”请求，请求返回即是“二维码展示页面”，该页面是动态生成的。</p><p>该请求携带如下参数：</p><ul><li><code>appid</code>: 应用标识，与“开放平台”注册一致。</li><li><code>redirect_uri</code>: 回调 <code>url</code>, 与“开放平台”注册一致。</li></ul><p>返回的页面中包含一个 <code>uuid</code> 字段，该字段和二维码是绑定的。用于后续获取二维码和对应的状态。</p><p><img src="'+m+'" alt="微信登录二维码获取"></p></li><li><p>登录页面通过“短轮询”的方式，实时感知登录会话状态。</p><p>每次轮询都会携带当前二维码的 <code>uuid </code>（唯一会话标识），向微信服务器查询该会话的实时状态，包括“未扫码、已扫码待授权、已授权、二维码失效”四种，这是接口最核心的作用。</p><p><img src="'+u+'" alt="微信登录二维码状态获取"></p></li></ol>',20)]))}const T=i(g,[["render",h]]);export{P as __pageData,T as default};
